// インターフェースの定義
interface Drawable {
    void draw();
}

// CircleクラスはDrawableインターフェースを実装
class Circle implements Drawable {
    public void draw() {
        System.out.println("Draw circle");
        // 出力: "Draw circle"
    }
}

// RectangleクラスもDrawableインターフェースを実装
class Rectangle implements Drawable {
    public void draw() {
        System.out.println("Draw rectangle");
        // 出力: "Draw rectangle"
    }
}

// Drawable型の配列にCircleとRectangleのインスタンスを格納
Drawable[] drawables = {new Circle(), new Rectangle()};

// 各インスタンスのdrawメソッドを呼び出す
for (Drawable drawable : drawables) {
    drawable.draw();
}

// スーパークラス
class Animal {
    void sound() {
        System.out.println("This is an animal.");
        // 出力: "This is an animal."
    }
}

// サブクラス1
class Dog extends Animal {
    // soundメソッドをオーバーライド
    void sound() {
        System.out.println("Woof Woof");
        // 出力: "Woof Woof"
    }
}

// サブクラス2
class Cat extends Animal {
    // soundメソッドをオーバーライド
    void sound() {
        System.out.println("Meow Meow");
        // 出力: "Meow Meow"
    }
}

// スーパークラスの型で配列を宣言
Animal[] animals = {new Dog(), new Cat()};

// 各オブジェクトのsoundメソッドを呼び出す
for (Animal animal : animals) {
    animal.sound();
}

// 抽象クラス
