    void sound() {
        System.out.println("Woof Woof");
        // 出力: "Woof Woof"
    }
}

// サブクラス2
class Cat extends AbstractAnimal {
    // soundメソッドをオーバーライド
    void sound() {
        System.out.println("Meow Meow");
        // 出力: "Meow Meow"
    }
}

// スーパークラスの型で配列を宣言
AbstractAnimal[] animals = {new Dog(), new Cat()};

// 各オブジェクトのsoundメソッドを呼び出す
for (AbstractAnimal animal : animals) {
    animal.sound();
}

